public class Main {
    public static void main(String[] args) {
        int count = 3;
        while (count > 0) {
            System.out.println(count);
            count = count - 1;
        }
        System.out.println("liftoff");
    }
}

public class Main {
    public static void main(String[] args) {
        int i = 10;
        while (i < 5) {
            System.out.println("this never prints");
        }
        System.out.println("loop was skipped");
    }
}

